func solve(prices []int64, strategy []int64, k int64) int64 {
    n := len(prices)
    original_profit := int64(0)
    for i := 0; i < n; i++ {
        original_profit += strategy[i] * prices[i]
    }

    prefix_sum_prices := make([]int64, n+1)
    prefix_strategy := make([]int64, n+1)
    for i := 0; i < n; i++ {
        prefix_sum_prices[i+1] = prefix_sum_prices[i] + prices[i]
        prefix_strategy[i+1] = prefix_strategy[i] + strategy[i] * prices[i]
    }

    half_k := k / 2
    max_gain := int64(0)
    for i := 0; i <= n - int(k); i++ {
        start_second := i + half_k
        end_second := i + int(k) - 1
        sum_second := prefix_sum_prices[end_second+1] - prefix_sum_prices[start_second]
        original_contribution := prefix_strategy[i+int(k)] - prefix_strategy[i]
        gain := sum_second - original_contribution
        if gain > max_gain {
            max_gain = gain
        }
    }

    return original_profit + max_gain
}
